def summarize_by_status(records):
summary = {}

for record in records:
    status = record.get("status") or "unknown"

    try:
        amount = float(record.get("amount", 0.0) or 0.0)
    except (TypeError, ValueError):
        amount = 0.0

    if status not in summary:
        summary[status] = {
            "count": 0,
            "total_amount": 0.0,
        }

    summary[status]["count"] += 1
    summary[status]["total_amount"] += amount

for status, data in summary.items():
    total = round(data["total_amount"], 2)
    count = data["count"]
    data["total_amount"] = total
    data["average_amount"] = round(total / count, 2) if count else 0.0

return summary

