def normalize_emails(emails):
seen = set()
result = []

for email in emails:
    normalized = str(email).strip().lower()
    if not normalized:
        continue
    if normalized.count("@") != 1:
        continue
    if normalized in seen:
        continue

    seen.add(normalized)
    result.append(normalized)

return result

