function summarizeOrders(orders) {
  const summary = {};

  for (const order of orders) {
    const customerId = order.customerId || "unknown";
    const numericTotal = Number(order.total);
    const total = Number.isFinite(numericTotal) ? numericTotal : 0;

    if (!summary[customerId]) {
      summary[customerId] = { count: 0, total: 0 };
    }

    summary[customerId].count += 1;
    summary[customerId].total += total;
  }

  for (const customerId of Object.keys(summary)) {
    const item = summary[customerId];
    item.total = Number(item.total.toFixed(2));
    item.average = Number((item.total / item.count).toFixed(2));
  }

  return summary;
}

