function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function retryAsync(operation, attempts, delayMs) {
  if (attempts < 1) {
    throw new Error("attempts must be positive");
  }

  let lastError;

  for (let attempt = 1; attempt <= attempts; attempt++) {
    try {
      return await operation();
    } catch (error) {
      lastError = error;
      if (attempt < attempts) {
        await sleep(delayMs);
      }
    }
  }

  throw lastError;
}

