type Task = {
  id: string;
  status: "todo" | "doing" | "done";
  points?: number;
};

type TaskSummary = {
  todo: number;
  doing: number;
  done: number;
  totalPoints: number;
};

function summarizeTasks(tasks: Task[]): TaskSummary {
  const summary: TaskSummary = {
    todo: 0,
    doing: 0,
    done: 0,
    totalPoints: 0,
  };

  for (const task of tasks) {
    summary[task.status] += 1;
    summary.totalPoints += typeof task.points === "number" ? task.points : 0;
  }

  return summary;
}

