def format_currency(amounts, symbol="$"):
formatted = []

for amount in amounts:
    try:
        value = float(amount)
    except (TypeError, ValueError):
        continue

    if value < 0:
        formatted.append(f"-{symbol}{abs(value):.2f}")
    else:
        formatted.append(f"{symbol}{value:.2f}")

return formatted

